package bench

import "testing"

// The pinned checksum vector from spec/design/benchmarks.md §6 (generated by the
// independent Ruby reference): rows (1, NULL, 'abc') and (-7).
func TestChecksumVector(t *testing.T) {
	c := NewChecksum()
	c.Int(1)
	c.Null()
	c.Text("abc")
	c.EndRow()
	c.Int(-7)
	c.EndRow()
	if got := c.Hex(); got != "dd6e60407d30d28b" {
		t.Errorf("checksum: got %s, want dd6e60407d30d28b", got)
	}
}
